# Day/month name arrays for use in JS rendering
DAY_NAMES = {
    "he": ["ראשון","שני","שלישי","רביעי","חמישי","שישי","שבת"],
    "en": ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"],
    "ar": ["الأحد","الاثنين","الثلاثاء","الأربعاء","الخميس","الجمعة","السبت"],
    "ru": ["Воскресенье","Понедельник","Вторник","Среда","Четверг","Пятница","Суббота"],
}
DAY_NAMES_SHORT = {
    "he": ["א","ב","ג","ד","ה","ו","ש"],
    "en": ["Su","Mo","Tu","We","Th","Fr","Sa"],
    "ar": ["أ","ث","ث","ر","خ","ج","س"],
    "ru": ["Вс","Пн","Вт","Ср","Чт","Пт","Сб"],
}
MONTH_NAMES_SHORT = {
    "he": ["ינו","פבר","מרץ","אפר","מאי","יונ","יול","אוג","ספט","אוק","נוב","דצמ"],
    "en": ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"],
    "ar": ["ينا","فبر","مار","أبر","ماي","يون","يول","أغس","سبت","أكت","نوف","ديس"],
    "ru": ["янв","фев","мар","апр","май","июн","июл","авг","сен","окт","ноя","дек"],
}


def get_ui_strings(lang):
    """Return a flat {key: value} dict for the given language.

    Falls back to English for any missing translations.
    """
    if lang not in ("he", "en", "ar", "ru"):
        lang = "en"
    return {k: v.get(lang) or v.get("en") or "" for k, v in UI_STRINGS.items()}


def get_day_names(lang):
    if lang not in DAY_NAMES:
        lang = "en"
    return {
        "long": DAY_NAMES[lang],
        "short": DAY_NAMES_SHORT[lang],
        "months_short": MONTH_NAMES_SHORT[lang],
    }
